                        ) >= 0 &&
                        (
                            IsBlank(DadosSERVICO.'Visualização do Motorista') ||
                            (
                                !IsBlank(DadosSERVICO.'Visualização do Motorista') &&
                                DateDiff(
                                    DadosSERVICO.'Visualização do Motorista',
                                    DadosSERVICO.'Data de Modificação',
                                    TimeUnit.Seconds
                                ) > 10
                            )
                        ),
                        1,

                        // PRIORIDADE 3 — Nunca visualizado OU editado após visualização e motorista não viu
                        IsBlank(DadosSERVICO.'Visualização do Motorista') ||
                        (
                            !IsBlank(DadosSERVICO.'Visualização do Motorista') &&
                            DateDiff(
                                DadosSERVICO.'Visualização do Motorista',
                                DadosSERVICO.'Data de Modificação',
                                TimeUnit.Seconds
                            ) > 10
                        ),
                        3,

                        // PRIORIDADE 10 — Receber = Sim (sempre, independente de visualização)
                        DadosSERVICO.Receber = true,
                        10,

                        // NENHUM — item normal, sem destaque
                        0
                    ),

                    "TROCA",
                    If(
                        // PRIORIDADE 1 — Saída em menos de 30 min E não visto ou editado após visualização
                        DateDiff(
                            Now(),
                            DadosTROCAGeral.'Data e horário de saída',
                            TimeUnit.Minutes
                        ) <= 30 &&
                        DateDiff(
                            Now(),
                            DadosTROCAGeral.'Data e horário de saída',
                            TimeUnit.Minutes
                        ) >= 0 &&
                        (
                            IsBlank(DadosTROCAGeral.'Visualização do Motorista') ||
                            (
                                !IsBlank(DadosTROCAGeral.'Visualização do Motorista') &&
                                DateDiff(
                                    DadosTROCAGeral.'Visualização do Motorista',
                                    DadosTROCAGeral.'Data de Modificação',
                                    TimeUnit.Seconds
                                ) > 10
                            )
                        ),
                        1,

                        // PRIORIDADE 3 — Nunca visualizado OU editado após visualização e motorista não viu
                        IsBlank(DadosTROCAGeral.'Visualização do Motorista') ||
                        (
                            !IsBlank(DadosTROCAGeral.'Visualização do Motorista') &&
                            DateDiff(
                                DadosTROCAGeral.'Visualização do Motorista',
                                DadosTROCAGeral.'Data de Modificação',
                                TimeUnit.Seconds
                            ) > 10
                        ),
                        3,

                        0
                    ),

                    "MANUTENCAO",
                    If(
                        // PRIORIDADE 1 — Saída em menos de 30 min E não visto ou editado após visualização
                        DateDiff(
                            Now(),
                            DadosMANUTENCAOGeral.'Data e horário de saída',
                            TimeUnit.Minutes
                        ) <= 30 &&
                        DateDiff(
                            Now(),
                            DadosMANUTENCAOGeral.'Data e horário de saída',
                            TimeUnit.Minutes
                        ) >= 0 &&
                        (
                            IsBlank(DadosMANUTENCAOGeral.'Visualização do Motorista') ||
                            (
                                !IsBlank(DadosMANUTENCAOGeral.'Visualização do Motorista') &&
                                DateDiff(
                                    DadosMANUTENCAOGeral.'Visualização do Motorista',
                                    DadosMANUTENCAOGeral.'Data de Modificação',
                                    TimeUnit.Seconds
                                ) > 10
                            )
                        ),
                        1,

                        // PRIORIDADE 3 — Nunca visualizado OU editado após visualização e motorista não viu
                        IsBlank(DadosMANUTENCAOGeral.'Visualização do Motorista') ||
                        (
                            !IsBlank(DadosMANUTENCAOGeral.'Visualização do Motorista') &&
                            DateDiff(
                                DadosMANUTENCAOGeral.'Visualização do Motorista',
                                DadosMANUTENCAOGeral.'Data de Modificação',
                                TimeUnit.Seconds
                            ) > 10
                        ),
                        3,

                        0
                    ),

                    // HEADER não exibe ícone
                    0
                )
                // =====================================================================
                // FIM DO CAMPO IconePrioridade
                // =====================================================================

            )
        );
        With(
            {t: Today()},
            ForAll(
                SortByColumns(
                    RenameColumns(
                        Distinct(
                            colAgendaUI,
                            DataChave
                        ),
                        Value,
                        DataChave
                    ),
                    "DataChave",
                    SortOrder.Ascending
                ) As D,
                Collect(
                    colAgendaUI,
                    {
                        Tipo: "HEADER",
                        DtOrdem: DateTimeValue(
                            Text(
                                D.DataChave,
                                "[$-en-US]yyyy-mm-dd"
                            ) & " 00:00"
                        ),
                        DtLocal: DateTimeValue(
                            Text(
                                D.DataChave,
                                "[$-en-US]yyyy-mm-dd"
                            ) & " 00:00"
                        ),
                        DataChave: D.DataChave,
                        TituloData: "Serviços de " & If(
                            D.DataChave = t,
                            "HOJE",
                            D.DataChave = DateAdd(
                                t,
                                1
                            ),
                            "AMANHÃ",
                            D.DataChave = DateAdd(
                                t,
                                -1
                            ),
                            "ONTEM",
                            With(
    {_dia: Weekday(D.DataChave, StartOfWeek.Sunday)},
    Switch(
        _dia,
        1, "DOMINGO",
        2, "SEGUNDA",
        3, "TERÇA",
        4, "QUARTA",
        5, "QUINTA",
        6, "SEXTA",
        7, "SÁBADO"
    )
)
                        ),
                        Seta: "▾",
                        DadosSERVICO: Blank(),
                        DadosTROCA: Blank(),
                        DadosTROCAGeral: Blank(),
                        DadosMANUTENCAO: Blank(),
                        DadosMANUTENCAOGeral: Blank(),
                        SearchText: "",
                        IconePrioridade: 0
                    }
                )
            )
        );
        ClearCollect(
            colAgendaUI,
            SortByColumns(
                colAgendaUI,
                "DtLocal",
                SortOrder.Ascending,
                "Tipo",
                SortOrder.Ascending
            )
        )
    );
    Set(
        varLoading,
        false
    )
)

